func (this *GlobalSpecType) Equal(that interface{}) bool {
	if that == nil {
		return this == nil
	}

	that1, ok := that.(*GlobalSpecType)
	if !ok {
		that2, ok := that.(GlobalSpecType)
		if ok {
			that1 = &that2
		} else {
			return false
		}
	}
	if that1 == nil {
		return this == nil
	} else if this == nil {
		return false
	}
	if !this.DdosProfile.Equal(that1.DdosProfile) {
		return false
	}
	if !this.AdvancedTcpProfile.Equal(that1.AdvancedTcpProfile) {
		return false
	}
	if len(this.Irules) != len(that1.Irules) {
		return false
	}
	for i := range this.Irules {
		if !this.Irules[i].Equal(that1.Irules[i]) {
			return false
		}
	}
	if !this.VirtualServer.Equal(that1.VirtualServer) {
		return false
	}
	if len(this.TrafficPolicies) != len(that1.TrafficPolicies) {
		return false
	}
	for i := range this.TrafficPolicies {
		if !this.TrafficPolicies[i].Equal(that1.TrafficPolicies[i]) {
			return false
		}
	}
	return true
}
